package com.hospital.management.validation;import com.hospital.management.model.DoctorScheduleForm;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;
class DoctorScheduleValidatorTest{DoctorScheduleValidator v=new DoctorScheduleValidator();@Test void valid(){assertFalse(v.validate(f()).hasErrors());}@Test void invalidDoctor(){DoctorScheduleForm f=f();f.setDoctorId(null);assertTrue(v.validate(f).hasErrors());}@Test void invalidDay(){DoctorScheduleForm f=f();f.setDayOfWeek("FUNDAY");assertTrue(v.validate(f).hasErrors());}@Test void invalidStart(){DoctorScheduleForm f=f();f.setStartTime("9am");assertTrue(v.validate(f).hasErrors());}@Test void invalidEnd(){DoctorScheduleForm f=f();f.setEndTime("25:00");assertTrue(v.validate(f).hasErrors());}@Test void endBeforeStart(){DoctorScheduleForm f=f();f.setEndTime("08:00");assertTrue(v.validate(f).hasErrors());}@Test void invalidDuration(){DoctorScheduleForm f=f();f.setSlotDurationMinutes("2");assertTrue(v.validate(f).hasErrors());}@Test void longerThanWindow(){DoctorScheduleForm f=f();f.setSlotDurationMinutes("180");assertTrue(v.validate(f).hasErrors());}@Test void nonDivisible(){DoctorScheduleForm f=f();f.setSlotDurationMinutes("50");assertTrue(v.validate(f).hasErrors());}private DoctorScheduleForm f(){DoctorScheduleForm f=new DoctorScheduleForm();f.setDoctorId(1L);f.setDayOfWeek("MONDAY");f.setStartTime("09:00");f.setEndTime("11:00");f.setSlotDurationMinutes("30");f.setAvailable(true);return f;}}
